import{_ as a,o as t,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"49. Daylight Saving","description":"","frontmatter":{"title":"49. Daylight Saving","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","overtime","shift-work"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/hours-of-work/49-daylight-saving.md","filePath":"ebas/has-managers-admin/common-terms/hours-of-work/49-daylight-saving.md"}'),n={name:"ebas/has-managers-admin/common-terms/hours-of-work/49-daylight-saving.md"};function s(r,e,h,l,m,d){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_49-daylight-saving" tabindex="-1">49. Daylight Saving <a class="header-anchor" href="#_49-daylight-saving" aria-label="Permalink to &quot;49. Daylight Saving&quot;">​</a></h1><p>See also <a href="/eba/ebas/has-managers-admin/common-terms/employment-types/25-fixed-term-employment.html">clause 25</a> of Section 2 and <a href="/eba/ebas/has-managers-admin/common-terms/preliminary/10-best-practice-employment-commitment.html">clause 10</a> of Section 3 (Overtime) and clause 47 (Accrued Days Off) of Section 1.</p><p><strong>49.1</strong> Despite the overtime provisions of this Agreement, if an Employee works on a shift during which time changes because of the introduction of, or cessation to, daylight saving, that Employee will be paid for the actual hours worked at the applicable ordinary time rate of pay (including any applicable shift allowances, allowances ordinarily payable in respect of the shift and special rates for Saturdays and Sundays). Example: An Employee is rostered to work a ten hour night shift from 9pm through to 7:30am (including a 30 minute meal break). During the course of this shift, the clock is wound forward one hour due to the commencement of daylight saving. The Employee therefore works nine hours. The Employee is paid nine hours at the applicable ordinary time rate of pay (including any shift allowances, allowances ordinarily payable in respect of this shift and special rates for Saturdays and Sundays). Example: An Employee is rostered in a ten hour night shift from 9pm through to 7.30am (including a 30 minute meal break). During the course of this shift, the clock is wound back one hour due to the cessation of daylight saving. The Employee therefore works 11 hours. The Employee is paid 11 hours at the ordinary time rate of pay (including any shift allowances, allowances ordinarily payable in respect of this shift and special rates for Saturdays and</p><p>Sundays). No overtime is paid for the additional hour worked.</p><p><strong>49.2</strong> For the purpose of calculating accrued days off, Employees who work on a shift during which time changes because of the introduction of, or cessation to, daylight saving, will be taken to have worked the standard hours for a night shift in accordance with the roster.</p><p>Plain language terms: DST.</p>',6)])])}const f=a(n,[["render",s]]);export{p as __pageData,f as default};
